const response = $input.first().json;
const interpretation = response.content?.[0]?.text || 'Ошибка: пустой ответ от Claude';

const buildPrompt = $('Build Prompt').first().json;
const lastNight = buildPrompt.lastNight;
const ctx = buildPrompt.ctx;

const parts = [];

if (lastNight?.duration_minutes) {
  const h = Math.floor(lastNight.duration_minutes / 60);
  const m = lastNight.duration_minutes % 60;
  let sleep = `🌙 ${h}ч${m.toString().padStart(2, '0')}м`;
  if (lastNight.source) sleep += ` [${lastNight.source}]`;
  if (lastNight.deep_minutes) {
    sleep += ` (💜${lastNight.deep_minutes} 🧠${lastNight.rem_minutes || '?'} 💚${lastNight.light_minutes || '?'})`;
  }
  if ((lastNight.segments || 1) > 1) {
    sleep += ` ⚠${lastNight.segments}ч`;
  }
  parts.push(sleep);
} else {
  parts.push('🌙 нет данных о сне');
}

if (lastNight?.min_heart_rate) parts.push(`❤️ ${lastNight.min_heart_rate}`);
if (lastNight?.avg_spo2) parts.push(`🫁 ${lastNight.avg_spo2}%`);
if (ctx?.steps_daily?.[0]?.steps) parts.push(`🚶 ${ctx.steps_daily[0].steps}`);

const bb = ctx?.body_battery_daily?.[0];
if (bb?.start_value) parts.push(`🔋 ${bb.start_value}`);

const tl = ctx?.training_load_current;
if (tl?.status) {
  const statusShort = { LOW: 'LOW', OPTIMAL: 'OPT', HIGH: 'HIGH', VERY_HIGH: 'V.HIGH' }[tl.status] || tl.status;
  parts.push(`📈 ${statusShort}`);
}

const kcalOut = ctx?.calories_daily?.[0]?.kcal_total;
const kcalIn = ctx?.nutrition_daily?.[0]?.calories_in;
if (kcalOut && kcalIn) {
  const balance = kcalIn - kcalOut;
  const sign = balance >= 0 ? '+' : '';
  parts.push(`🍽️ ${kcalIn}/${kcalOut} (${sign}${balance})`);
} else if (kcalOut) {
  parts.push(`🔥 ${kcalOut}`);
}

if (ctx?.weight?.[0]?.weight_kg) parts.push(`⚖️ ${ctx.weight[0].weight_kg}кг`);

const header = parts.join(' | ') + '\n\n';
const telegramText = header + interpretation;

return [{ json: {
  interpretation,
  telegramText,
  tokens_in: response.usage?.input_tokens,
  tokens_out: response.usage?.output_tokens,
  model: response.model
} }];
